1	export type Cell = [number, number];
2	
3	function countNeighbors(cell: Cell, liveCells: Cell[]): number {
4	  const [x, y] = cell;
5	  return liveCells.filter(
6	    ([nx, ny]) => !(nx === x && ny === y) && Math.abs(nx - x) <= 1 && Math.abs(ny - y) <= 1
7	  ).length;
8	}
9	
10	export function nextGeneration(liveCells: Cell[]): Cell[] {
11	  return liveCells.filter((cell) => {
12	    const neighborCount = countNeighbors(cell, liveCells);
13	    return neighborCount === 2 || neighborCount === 3;
14	  });
15	}
