it("should keep a cell alive that has exactly 3 live neighbors (survival)", () => {
  // T-shape: cell (1,0) has 3 neighbors: (0,0), (2,0), (1,1) → survives
  const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
  expect(result).toContainEqual([1, 0]);
});
